@namespace sv_54ec429d0d7e48d489632e2cdddd3f92.Components.Pages.Catalog

<div class="product-grid-container">
    <div class="toolbar">
        <div class="sort-control">
            <label for="sort-select">Sort by:</label>
            <select id="sort-select" value="@CurrentSort" @onchange="HandleSortChange">
                <option value="price_asc">Price: Low to High</option>
                <option value="price_desc">Price: High to Low</option>
                <option value="name_asc">Name: A-Z</option>
                <option value="rating_desc">Rating: Highest</option>
            </select>
        </div>
        <span class="results-summary">
            @if (Products is not null && Products.TotalCount > 0)
            {
                var start = (Products.Page - 1) * Products.PageSize + 1;
                var end = Math.Min(Products.Page * Products.PageSize, Products.TotalCount);
                @($"Showing {start}–{end} of {Products.TotalCount} products")
            }
        </span>
    </div>

    @if (Products is null || Products.Items is null)
    {
        <div class="state-message">Loading products...</div>
    }
    else if (Products.Items.Count == 0)
    {
        <div class="state-message">No products found. Try adjusting your filters.</div>
    }
    else
    {
        <div class="product-grid">
            @foreach (var product in Products.Items)
            {
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            }
        </div>

        @if (TotalPages > 1)
        {
            <nav class="pagination" aria-label="Product pagination">
                <button class="page-btn"
                        disabled="@(Products.Page <= 1)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Products.Page - 1))">
                    Previous
                </button>

                @for (int i = 1; i <= TotalPages; i++)
                {
                    var page = i;
                    <button class="page-btn @(page == Products.Page ? "active" : "")"
                            @onclick="@(() => OnPageChanged.InvokeAsync(page))">
                        @page
                    </button>
                }

                <button class="page-btn"
                        disabled="@(Products.Page >= TotalPages)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Products.Page + 1))">
                    Next
                </button>
            </nav>
        }
    }
</div>

@code {
    [Parameter]
    public PagedResult<Product>? Products { get; set; }

    [Parameter]
    public string CurrentSort { get; set; } = "price_asc";

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int TotalPages => Products is not null && Products.PageSize > 0
        ? (int)Math.Ceiling((double)Products.TotalCount / Products.PageSize)
        : 0;

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

.product-grid-container {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    padding: 1.5rem;
    height: 100%;
}

.toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 1rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #e0e0e0;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control label {
    font-size: 0.9rem;
    color: #555;
}

.sort-control select {
    padding: 0.4rem 0.6rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

.results-summary {
    font-size: 0.9rem;
    color: #666;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.5rem;
}

.state-message {
    text-align: center;
    padding: 3rem 1rem;
    color: #888;
    font-size: 1.1rem;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.25rem;
    padding-top: 1.5rem;
    flex-wrap: wrap;
}

.page-btn {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.15s;
}

.page-btn:hover:not(:disabled):not(.active) {
    background: #f0f0f0;
}

.page-btn.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.page-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@page "/catalog"
@namespace sv_54ec429d0d7e48d489632e2cdddd3f92.Components.Pages.Catalog
@using sv_54ec429d0d7e48d489632e2cdddd3f92
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_errorMessage is not null)
{
    <div class="error-banner">
        <p>@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <ProductFilterPanel Categories="_categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />

        <ProductGrid Products="_products"
                     CurrentSort="@_sortBy"
                     OnSortChanged="HandleSortChanged"
                     OnPageChanged="HandlePageChanged"
                     OnProductSelected="HandleProductSelected"
                     OnAddToCart="HandleAddToCart" />
    </div>
}

@code {
    private PagedResult<Product>? _products;
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private string? _errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _errorMessage = null;
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            _products = productsTask.Result;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _errorMessage = null;
            _products = null; // show loading state
            _products = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire up cart service when available
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

