{"file_text": "@namespace sv_54ec429d0d7e48d489632e2cdddd3f92.Components.Pages.Catalog

<div class="product-grid-container">
    <div class="toolbar">
        <div class="sort-control">
            <label for="sort-select">Sort by:</label>
            <select id="sort-select" value="@CurrentSort" @onchange="HandleSortChange">
                <option value="price_asc">Price: Low to High</option>
                <option value="price_desc">Price: High to Low</option>
                <option value="name_asc">Name: A-Z</option>
                <option value="rating_desc">Rating: Highest</option>
            </select>
        </div>
        <span class="results-summary">
            @if (Products is not null && Products.TotalCount > 0)
            {
                var start = (Products.Page - 1) * Products.PageSize + 1;
                var end = Math.Min(Products.Page * Products.PageSize, Products.TotalCount);
                @($"Showing {start}–{end} of {Products.TotalCount} products")
            }
        </span>
    </div>

    @if (Products is null || Products.Items is null)
    {
        <div class="state-message">Loading products...</div>
    }
    else if (Products.Items.Count == 0)
    {
        <div class="state-message">No products found. Try adjusting your filters.</div>
    }
    else
    {
        <div class="product-grid">
            @foreach (var product in Products.Items)
            {
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            }
        </div>

        @if (TotalPages > 1)
        {
            <nav class="pagination" aria-label="Product pagination">
                <button class="page-btn"
                        disabled="@(Products.Page <= 1)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Products.Page - 1))">
                    Previous
                </button>

                @for (int i = 1; i <= TotalPages; i++)
                {
                    var page = i;
                    <button class="page-btn @(page == Products.Page ? "active" : "")"
                            @onclick="@(() => OnPageChanged.InvokeAsync(page))">
                        @page
                    </button>
                }

                <button class="page-btn"
                        disabled="@(Products.Page >= TotalPages)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Products.Page + 1))">
                    Next
                </button>
            </nav>
        }
    }
</div>

@code {
    [Parameter]
    public PagedResult<Product>? Products { get; set; }

    [Parameter]
    public string CurrentSort { get; set; } = "price_asc";

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int TotalPages => Products is not null && Products.PageSize > 0
        ? (int)Math.Ceiling((double)Products.TotalCount / Products.PageSize)
        : 0;

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}
