.filter-panel {
    background: #fafafa;
    border-right: 1px solid #e0e0e0;
    padding: 1.5rem;
    height: 100%;
    overflow-y: auto;
}

.filter-panel h2 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
}

.filter-section {
    margin-bottom: 1.5rem;
}

.filter-section h3 {
    font-size: 0.95rem;
    margin: 0 0 0.5rem;
    color: #555;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.4rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.price-inputs {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
    color: #555;
}

.price-inputs input {
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
    margin-top: 0.2rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply {
    padding: 0.5rem 1rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    padding: 0.5rem 1rem;
    background: transparent;
    color: #666;
    border: 1px solid #ccc;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-clear:hover {
    background: #f0f0f0;
}

