.catalog-layout {
    display: flex;
    gap: 0;
    min-height: 600px;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    margin-top: 1rem;
}

.catalog-layout > :first-child {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-layout > :last-child {
    flex: 1;
}

.error-banner {
    background: #fde8e8;
    border: 1px solid #f5c6c6;
    color: #842029;
    padding: 1rem 1.5rem;
    border-radius: 6px;
    margin-top: 1rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
}

.error-banner p {
    margin: 0;
}

.error-banner button {
    padding: 0.4rem 1rem;
    background: #842029;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.error-banner button:hover {
    background: #6a1a21;
}

